parameters.content:
// Inicializar config
$input.first().json = {
  config: {
    KPSULA_HOST: "https://pokepok.kpsula.app",
    KPSULA_API_KEY: "TU_API_KEY_AQUI",
    KPSULA_WEBHOOK_SECRET: "TU_SECRET_AQUI",
    TELEGRAM_BOT_TOKEN: "TU_BOT_TOKEN_AQUI"
  }
};
return $input.first();

// Parse foto de Telegram
const msg = $input.first().json.message;
const chatId = msg.chat.id;
const photoId = msg.photo[msg.photo.length - 1].file_id;

return {
  chatId,
  photoId,
  config: $input.first().json.config
};

// Cargar orden_id de sesión
const sessionKey = `session_${$node["Parse Photo"].json.chatId}`;
const workflowData = await $getWorkflowData(sessionKey);
const ordenId = workflowData ? workflowData.orden_id : null;

if (!ordenId) {
  throw new Error(`No hay orden activa para el chat ${$node["Parse Photo"].json.chatId}`);
}

return {
  chatId: $node["Parse Photo"].json.chatId,
  photoId: $node["Parse Photo"].json.photoId,
  ordenId: ordenId,
  config: $input.first().json.config
};

parameters.url:
type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4.1,
      "position": [900, 300]
    },
    {
      "parameters": {
        "content": "// Preparar multipart form-data para POST /ordenes/{id}/comprobante\nconst imageBuffer = $node[\"download-image\"].json.body; // arraybuffer\nconst ordenId = $node[\"load-orden-id\"].json.ordenId;\nconst tipo = 'manual'; // tipo de comprobante\n\nreturn {\n  ordenId: ordenId,\n  imageBinary: imageBuffer,\n  tipo: tipo,\n  config: $input.first().json.config,\n  chatId: $node[\"load-orden-id\"].json.chatId\n};",
        "language": "javaScript"
      },
      "id": "prepare-multipart",
      "name": "Prepare Multipart Payload",
      "type": "n8n-nodes-base.code",
      "typeVersion": 2,
      "position": [1100, 200]
    },
    {
      "parameters": {
        "url": "{{ $node[\"prepare-multipart\"].json.config.KPSULA_HOST + '/api/v1/delivery/ordenes/' + $node[\"prepare-multipart\"].json.ordenId + '/comprobante' }}",
        "method": "POST",
        "headerParameters": {
          "parameters": [
            {
              "name": "X-API-Key",
              "value": "{{ $node[\"prepare-multipart\"].json.config.KPSULA_API_KEY }}"
            }
          ]
        },
        "options": {
          "formData": {
            "data": [
              {
                "key": "tipo",
                "value": "manual"
              },
              {
                "key": "files",
                "type": "file",
                "fileContent": "{{ $node[\"prepare-multipart\"].json.imageBinary }}",
                "fileName": "comprobante.jpg"
              }
            ]
          }
        }
      },
      "id": "post-comprobante",
      "name": "POST /ordenes/{id}/comprobante",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4.1,
      "position": [1300, 200]
    },
    {
      "parameters": {
        "chatId": "{{ $node[\"prepare-multipart\"].json.chatId }}",
        "messageType": "text",
        "text": "✅ Comprobante recibido!\n\nTu orden está en validación. Te avisaremos cuando sea confirmada."
      },
      "id": "respond-comprobante-ok",
      "name": "Responder: Comprobante OK",
      "type": "n8n-nodes-base.telegram",
      "typeVersion": 1,
      "position": [1500, 200],
      "credentials": {
        "telegramApi": "telegram-bot-token"
      }
    },
    {
      "parameters": {
        "chatId": "{{ $node[\"load-orden-id\"].json.chatId }}",
        "messageType": "text",
        "text": "❌ Error: No tienes una orden activa. Inicia una nueva."
      },
      "id": "respond-no-orden",
      "name": "Responder: Sin orden",
      "type": "n8n-nodes-base.telegram",
      "typeVersion": 1,
      "position": [700, 400],
      "credentials": {
        "telegramApi": "telegram-bot-token"
      },
      "continueOnFail": true
    }
  ],
  "connections": {
    "telegram-trigger-photo": {
      "main": [[{ "node": "set-config-photo", "type": "main", "index": 0 }]]
    },
    "set-config-photo": {
      "main": [[{ "node": "parse-photo", "type": "main", "index": 0 }]]
    },
    "parse-photo": {
      "main": [[{ "node": "load-orden-id", "type": "main", "index": 0 }]]
    },
    "load-orden-id": {
      "main": [
        [{ "node": "get-file-info", "type": "main", "index": 0 }],
        [{ "node": "respond-no-orden", "type": "main", "index": 0 }]
      ]
    },
    "get-file-info": {
      "main": [[{ "node": "download-image", "type": "main", "index": 0 }]]
    },
    "download-image": {
      "main": [[{ "node": "prepare-multipart", "type": "main", "index": 0 }]]
    },
    "prepare-multipart": {
      "main": [[{ "node": "post-comprobante", "type": "main", "index": 0 }]]
    },
    "post-comprobante": {
      "main": [[{ "node": "respond-comprobante-ok", "type": "main", "index": 0 }]]
    }
  }
}
